def fast_sort(arr):
    arr = list(arr)
    n = len(arr)
    if n <= 1:
        return arr
    def _insertion_sort(a, lo, hi):
        for i in range(lo + 1, hi):
            key = a[i]
            j = i - 1
            while j >= lo and a[j] > key:
                a[j + 1] = a[j]
                j -= 1
            a[j + 1] = key
    def _heapsort(a, lo, hi):
        size = hi - lo
        def sift_down(start, end):
            root = start
            while True:
                child = 2 * root + 1
                if child >= end:
                    break
                if child + 1 < end and a[lo + child] < a[lo + child + 1]:
                    child += 1
                if a[lo + root] < a[lo + child]:
                    a[lo + root], a[lo + child] = a[lo + child], a[lo + root]
                    root = child
                else:
                    break
        for start in range(size // 2 - 1, -1, -1):
            sift_down(start, size)
        for end in range(size - 1, 0, -1):
            a[lo], a[lo + end] = a[lo + end], a[lo]
            sift_down(0, end)
    def _sort(a, lo, hi, depth_limit):
        while hi - lo > 32:
            if depth_limit == 0:
                _heapsort(a, lo, hi)
                return
            depth_limit -= 1
            mid = (lo + hi) // 2
            s = hi - lo
            if s > 100:
                q1 = lo + s // 4
                q3 = lo + 3 * s // 4
                candidates = [(a[lo], lo), (a[q1], q1), (a[mid], mid), (a[q3], q3), (a[hi - 1], hi - 1)]
                candidates_sorted = [c for c in candidates]
                candidates_sorted.sort(key=lambda x: x[0])
                pivot_val, pivot_idx = candidates_sorted[2]
            else:
                if a[lo] > a[mid]:
                    a[lo], a[mid] = a[mid], a[lo]
                if a[lo] > a[hi - 1]:
                    a[lo], a[hi - 1] = a[hi - 1], a[lo]
                if a[mid] > a[hi - 1]:
                    a[mid], a[hi - 1] = a[hi - 1], a[mid]
                pivot_val = a[mid]
                pivot_idx = mid
            a[pivot_idx], a[hi - 1] = a[hi - 1], a[pivot_idx]
            pivot = pivot_val
            lt, gt = lo, hi - 2
            i = lo
            while i <= gt:
                if a[i] < pivot:
                    a[i], a[lt] = a[lt], a[i]
                    lt += 1
                    i += 1
                elif a[i] > pivot:
                    a[i], a[gt] = a[gt], a[i]
                    gt -= 1
                else:
                    i += 1
            a[hi - 1], a[gt + 1] = a[gt + 1], a[hi - 1]
            _sort(a, gt + 2, hi, depth_limit)
            hi = lt
        _insertion_sort(a, lo, hi)
    depth = 2 * n.bit_length()
    _sort(arr, 0, n, depth)
    return arr
